   1 | import { TriggerAction, type ISdk } from "iii-sdk";
   2 | import type { Memory } from "../types.js";
   3 | import { KV, generateId, jaccardSimilarity } from "../state/schema.js";
   4 | import { StateKV } from "../state/kv.js";
   5 | import { withKeyedLock } from "../state/keyed-mutex.js";
   6 | import { memoryToObservation } from "../state/memory-utils.js";
   7 | import { deleteAccessLog } from "./access-tracker.js";
   8 | import { recordAudit } from "./audit.js";
   9 | import { getSearchIndex, vectorIndexAddGuarded, vectorIndexRemove, flushIndexSave } from "./search.js";
  10 | import { getAgentId } from "../config.js";
  11 | import { logger } from "../logger.js";
  12 | 
  13 | export function registerRememberFunction(sdk: ISdk, kv: StateKV): void {
  14 |   sdk.registerFunction("mem::remember",
  15 |     async (data: {
  16 |       content: string;
  17 |       type?: string;
  18 |       concepts?: string[];
  19 |       files?: string[];
  20 |       ttlDays?: number;
  21 |       sourceObservationIds?: string[];
  22 |       agentId?: string;
  23 |       project?: string;
  24 |     }) => {
  25 |       if (
  26 |         !data.content ||
  27 |         typeof data.content !== "string" ||
  28 |         !data.content.trim()
  29 |       ) {
  30 |         return { success: false, error: "content is required" };
  31 |       }
  32 |       if (data.files && !Array.isArray(data.files)) {
  33 |         return { success: false, error: "files must be an array" };
  34 |       }
  35 |       if (data.concepts && !Array.isArray(data.concepts)) {
  36 |         return { success: false, error: "concepts must be an array" };
  37 |       }
  38 |       if (data.sourceObservationIds && !Array.isArray(data.sourceObservationIds)) {
  39 |         return { success: false, error: "sourceObservationIds must be an array" };
  40 |       }
  41 |       const validTypes = new Set([
  42 |         "pattern",
  43 |         "preference",
  44 |         "architecture",
  45 |         "bug",
  46 |         "workflow",
  47 |         "fact",
  48 |       ]);
  49 |       const memType = validTypes.has(data.type || "")
  50 |         ? (data.type as Memory["type"])
  51 |         : "fact";
  52 | 
  53 |       const now = new Date().toISOString();
  54 |       // Normalize project early so every subsequent comparison and storage
  55 |       // operation uses the same cleaned value. Raw data.project must not be
  56 |       // referenced below this point.
  57 |       const project =
  58 |         typeof data.project === "string" && data.project.trim().length > 0
  59 |           ? data.project.trim()
  60 |           : undefined;
  61 | 
  62 |       return withKeyedLock("mem:remember", async () => {
  63 |         const existingMemories = await kv.list<Memory>(KV.memories);
  64 |         let supersededId: string | undefined;
  65 |         let supersededVersion = 1;
  66 |         let supersededMemory: Memory | undefined;
  67 |         const lowerContent = data.content.toLowerCase();
  68 |         for (const existing of existingMemories) {
  69 |           if (existing.isLatest === false) continue;
  70 |           // Never supersede a memory that belongs to a different project.
  71 |           // Both sides must have an explicit project for the guard to engage;
  72 |           // an unscoped memory (legacy, no project field) is treated as a
  73 |           // wildcard so pre-existing data is not stranded.
  74 |           if (project && existing.project && existing.project !== project) {
  75 |             continue;
  76 |           }
  77 |           const similarity = jaccardSimilarity(
  78 |             lowerContent,
  79 |             existing.content.toLowerCase(),
  80 |           );
  81 |           if (similarity > 0.7) {
  82 |             supersededId = existing.id;
  83 |             supersededVersion = existing.version...

